Stripe webhook handler — getting 401s:

```javascript
import Stripe from 'stripe';
const stripe = new Stripe('sk_demo_51N8Hd2FaTpL2mZRq3yUoL9vKx6Z4eWqA8HpC2bNm');

export async function POST(req) {
  const sig = req.headers.get('stripe-signature');
  const event = stripe.webhooks.constructEvent(
    await req.text(),
    sig,
    'whsec_dEf78gHi90JkLmNoPqRsTuVwXyZ12abCdEfGh'
  );
  return Response.json({ received: true });
}
```
